n, k = map(int, input().split())

matrix = [[0]*n for i in range(n)]

for i in range(n):
    for j in range(n):
        if i <= j:
            matrix[i][j] = 1

if k > n*n:
    print(-1)
else:
    for i in range(n):
        for j in range(n):
            if k > 0 and matrix[i][j] == 0:
                matrix[i][j] = 1
                k -= 1

    for i in range(n):
        for j in range(n):
            print(matrix[i][j], end=" ")
        print()
